// // This sign extender extends a 16-bit signed input to a 32-bit output. If the MSB is 0, it sign-extends by adding 16 zeros. If the MSB is 1, it zero-extends by adding 16 ones.
module top_module(imm, e_out);input [15:0] imm;
    output reg [31:0] e_out;

    always @(*) begin
        if (imm[15] == 0) begin
            e_out <= {16'h0000, imm};
        end
        else begin
            e_out <= {16'hFFFF, imm};
        end
    end
endmodule
